```

Then create platform/browser-extension/src/side-panel/components/BrowserToolsMenu.tsx following the PluginMenu pattern:

```tsx
import { Menu } from './retro/Menu';
import { MoreHorizontal, Server } from 'lucide-react';

interface BrowserToolsMenuProps {
  serverVersion?: string;
  className?: string;
}

const BrowserToolsMenu = ({ serverVersion, className }: BrowserToolsMenuProps) => (
  <div
    className={className}
    onClick={e => e.stopPropagation()}
    onKeyDown={e => {
      if (e.key === 'Enter' || e.key === ' ') e.stopPropagation();
    }}
    role="presentation">
    <Menu>
      <Menu.Trigger asChild>
        <button
          className="hover:bg-muted/50 flex h-6 w-6 items-center justify-center rounded"
          aria-label="Browser tools options">
          <MoreHorizontal className="h-4 w-4" />
        </button>
      </Menu.Trigger>
      <Menu.Content align="end">
        <Menu.Item disabled className="text-muted-foreground">
          <Server className="h-3.5 w-3.5" />
          Server {serverVersion ? `v${serverVersion}` : 'unknown'}
        </Menu.Item>
      </Menu.Content>
    </Menu>
  </div>
);

export { BrowserToolsMenu };
export type { BrowserToolsMenuProps };
```

Note: The `disabled` prop on `Menu.Item` makes it non-interactive (informational only). Check platform/browser-extension/src/side-panel/components/retro/Menu.tsx to verify the `disabled` prop is supported — Radix DropdownMenu.Item supports it natively.

Update BrowserToolsCard to accept `serverVersion?: string` and render:
```tsx
<BrowserToolsMenu
  serverVersion={serverVersion}
  className="flex shrink-0 items-center px-1"
/>
```

...between the AccordionPrimitive.Trigger closing tag and the Switch wrapper div. This matches PluginMenu's className exactly (`"flex shrink-0 items-center px-1"` at PluginCard.tsx line 138).
